mapper.select:
select reqno from patient_raw_data_change_task where status in
#{status}
and available_at <= #{now} and attempt_count < max_attempts group by reqno order by min(available_at), min(create_time) offset 0 rows fetch next #{limit} rows only

select r.id, r.reqno, r.data_date, r.clinical_notes, r.data_json, r.filter_data_json, r.struct_data_json, r.event_json, r.create_time, r.last_time from patient_raw_data r left join patient_raw_data_change_task t on t.patient_raw_data_id = r.id and t.raw_data_last_time = r.last_time where r.last_time is not null and t.id is null
and r.reqno in
#{reqno}
and r.last_time >= #{lastTimeFrom}
order by r.last_time asc, r.id asc offset 0 rows fetch next #{limit} rows only
